### Text Format

```rust
pub trait TextEncode {
    fn encode_text(&self) -> String;
}

pub trait TextDecode: Sized {
    fn decode_text(s: &str) -> Result<Self, Error>;
}

// Implementations
impl TextEncode for bool {
    fn encode_text(&self) -> String {
        if *self { "t" } else { "f" }.to_string()
    }
}

impl TextDecode for bool {
    fn decode_text(s: &str) -> Result<Self, Error> {
        match s {
            "t" | "true" | "1" => Ok(true),
            "f" | "false" | "0" => Ok(false),
            _ => Err(Error::Type(TypeError::bool(s))),
        }
    }
}

impl TextEncode for i32 {
    fn encode_text(&self) -> String {
        self.to_string()
    }
}

impl TextDecode for i32 {
    fn decode_text(s: &str) -> Result<Self, Error> {
        s.parse().map_err(|_| Error::Type(TypeError::int(s)))
    }
}

// Timestamp: "2023-01-15 10:30:00"
impl TextDecode for NaiveDateTime {
    fn decode_text(s: &str) -> Result<Self, Error> {
        // Try multiple formats
        for fmt in &["%Y-%m-%d %H:%M:%S%.f", "%Y-%m-%d %H:%M:%S", "%Y-%m-%dT%H:%M:%S%.f"] {
            if let Ok(dt) = NaiveDateTime::parse_from_str(s, fmt) {
                return Ok(dt);
            }
        }
        Err(Error::Type(TypeError::datetime(s)))
    }
}
