### Value Conversion

```rust
pub fn decode_value(oid: u32, data: Option<&[u8]>, format: Format) -> Result<Value, Error> {
    let Some(data) = data else {
        return Ok(Value::Null);
    };

    match (oid, format) {
        (oid::BOOL, Format::Binary) => Ok(Value::Bool(bool::decode_binary(data)?)),
        (oid::BOOL, Format::Text) => Ok(Value::Bool(bool::decode_text(std::str::from_utf8(data)?)?)),

        (oid::INT2, Format::Binary) => Ok(Value::SmallInt(i16::decode_binary(data)?)),
        (oid::INT2, Format::Text) => Ok(Value::SmallInt(i16::decode_text(std::str::from_utf8(data)?)?)),

        (oid::INT4, Format::Binary) => Ok(Value::Integer(i32::decode_binary(data)?)),
        (oid::INT4, Format::Text) => Ok(Value::Integer(i32::decode_text(std::str::from_utf8(data)?)?)),

        (oid::INT8, Format::Binary) => Ok(Value::BigInt(i64::decode_binary(data)?)),
        (oid::INT8, Format::Text) => Ok(Value::BigInt(i64::decode_text(std::str::from_utf8(data)?)?)),

        (oid::TEXT | oid::VARCHAR, _) => Ok(Value::Text(String::from_utf8(data.to_vec())?)),

        (oid::BYTEA, Format::Binary) => Ok(Value::Blob(data.to_vec())),
        (oid::BYTEA, Format::Text) => Ok(Value::Blob(decode_bytea_hex(data)?)),

        (oid::UUID, Format::Binary) => Ok(Value::Uuid(Uuid::decode_binary(data)?.into_bytes())),
        (oid::UUID, Format::Text) => Ok(Value::Uuid(Uuid::parse_str(std::str::from_utf8(data)?)?.into_bytes())),

        // ... more types

        _ => Err(Error::Type(TypeError::unknown_oid(oid))),
    }
}
